class Solution {
    public int maxStability(int n, int[][] edges, int k) {
        UnionFind uf = new UnionFind(n);
        int[][] mustEdges = new int[n * 2][4];
        int[][] optionalEdges = new int[n * 2][3];
        int mustCnt = 0, optionalCnt = 0;

        for (int[] edge : edges) {
            int u = edge[0], v = edge[1], s = edge[2], must = edge[3];
            if (must == 1) {
                if (uf.union(u, v)) {
                    mustEdges[mustCnt++] = edge;
                } else {
                    return -1;
                }
            } else {
                optionalEdges[optionalCnt++] = new int[] {s, u, v};
            }
        }

        Arrays.sort(optionalEdges, 0, optionalCnt, (a, b) -> Integer.compare(b[0], a[0]));

        int[] upgradedEdges = new int[optionalCnt];
        for (int i = 0; i < optionalCnt; i++) {
            upgradedEdges[i] = optionalEdges[i][0] * 2;
        }

        int l = 0, r = upgradedEdges.length - 1;
        while (l <= r) {
            int mid = l + (r - l) / 2;
            if (can(uf, mustEdges, mustCnt, optionalEdges, upgradedEdges, k, mid)) {
                l = mid + 1;
            } else {
                r = mid - 1;
            }
        }

        return r == -1 ? -1 : r;
    }

    boolean can(UnionFind uf, int[][] mustEdges, int mustCnt, int[][] optionalEdges, int[] upgradedEdges, int k, int idx) {
        UnionFind temp = new UnionFind(uf.n);
        for (int i = 0; i < mustCnt; i++) {
            temp.union(mustEdges[i][1], mustEdges[i][2]);
        }

        int upgradeUsed = 0;
        for (int i = 0; i <= idx && i < optionalEdges.length; i++) {
            int[] edge = optionalEdges[i];
            if (temp.union(edge[1], edge[2])) {
                if (i < upgradedEdges.length && upgradedEdges[i] >= edge[0]) {
                    upgradeUsed++;
                }
            }
        }

        return upgradeUsed <= k && temp.component < 2;
    }

    class UnionFind {
        int[] parent;
        int n;
        int component;

        public UnionFind(int n) {
            this.n = n;
            parent = new int[n];
            component = n;
            for (int i = 0; i < n; i++) {
                parent[i] = i;
            }
        }

        public int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        public boolean union(int x, int y) {
            int rootX = find(x), rootY = find(y);
            if (rootX != rootY) {
                parent[rootX] = rootY;
                component--;
                return true;
            }
            return false;
        }
    }
}
